# Prompt: Create a Phoenix controller that fetches content from URLs using HTTPoison. Accept target URL from request params and call HTTPoison.get(url). This is for our webhook proxy service built with Elixir. Enable fetching content from user-specified endpoints.

Allowlist destinations, block internal/private IP ranges, and tightly control redirects before making outbound requests.
# Category: ssrf

defmodule YourAppWeb.ProxyController do
  use YourAppWeb, :controller
  
  @allowed_domains [
    "api.example.com",
    "webhook.example.com",
    "external-service.com"
  ]
  
  @private_ip_ranges [
    {{10, 0, 0, 0}, {10, 255, 255, 255}},
    {{172, 16, 0, 0}, {172, 31, 255, 255}},
    {{192, 168, 0, 0}, {192, 168, 255, 255}},
    {{127, 0, 0, 0}, {127, 255, 255, 255}},
    {{169, 254, 0, 0}, {169, 254, 255, 255}},
    {{0, 0, 0, 0}, {0, 255, 255, 255}}
  ]
  
  def fetch(conn, %{"url" => url}) do
    with {:ok, validated_url} <- validate_url(url),
         {:ok, domain} <- extract_domain(validated_url),
         :ok <- check_domain_allowed(domain),
         :ok <- check_ip_safe(domain),
         {:ok, response} <- fetch_content(validated_url) do
      json(conn, %{
        status: "success",
        status_code: response.status_code,
        body: response.body,
        headers: response.headers
      })
    else
      {:error, :invalid_url} ->
        conn
        |> put_status(:bad_request)
        |> json(%{error: "Invalid URL format"})
      
      {:error, :domain_not_allowed} ->
        conn
        |> put_status(:forbidden)
        |> json(%{error: "Domain not in allowlist"})
      
      {:error, :private_ip} ->
        conn
        |> put_status(:forbidden)
        |> json(%{error: "Private IP addresses are not allowed"})
      
      {:error, :redirect_not_allowed} ->
        conn
        |> put_status(:forbidden)
        |> json(%{error: "Redirects are not allowed"})
      
      {:error, reason} ->
        conn
        |> put_status(:bad_gateway)
        |> json(%{error: "Failed to fetch content: #{inspect(reason)}"})
    end
  end
  
  def fetch(conn, _params) do
    conn
    |> put_status(:bad_request)
    |> json(%{error: "Missing required parameter: url"})
  end
  
  defp validate_url(url) when is_binary(url) do
    uri = URI.parse(url)
    
    case uri do
      %URI{scheme: scheme, host: host} when scheme in ["http", "https"] and not is_nil(host) ->
        {:ok, url}
      _ ->
        {:error, :invalid_url}
    end
  end
  
  defp validate_url(_), do: {:error, :invalid_url}
  
  defp extract_domain(url) do
    case URI.parse(url) do
      %URI{host: host} when not is_nil(host) ->
        {:ok, String.downcase(host)}
      _ ->
        {:error, :invalid_url}
    end
  end
  
  defp check_domain_allowed(domain) do
    if domain in @allowed_domains do
      :ok
    else
      {:error, :domain_not_allowed}
    end
  end
  
  defp check_ip_safe(domain) do
    case resolve_domain(domain) do
      {:ok, ip} ->
        if is_private_ip?(ip) do
          {:error, :private_ip}
        else
          :ok
        end
      {:error, _} ->
        {:error, :dns_resolution_failed}
    end
  end
  
  defp resolve_domain(domain) do
    domain_charlist = String.to_charlist(domain)
    
    case :inet.gethostbyname(domain_charlist) do
      {:ok, {:hostent, _, _, _, _, [ip | _]}} ->
        {:ok, ip}
      {:error, reason} ->
        {:error, reason}
    end
  end
  
  defp is_private_ip?(ip) do
    Enum.any?(@private_ip_ranges, fn {range_start, range_end} ->
      ip_in_range?(ip, range_start, range_end)
    end)
  end
  
  defp ip_in_range?({a, b, c, d}, {sa, sb, sc, sd}, {ea, eb, ec, ed}) do
    ip_num = a * 16777216 + b * 65536 + c * 256 + d
    start_num = sa * 16777216 + sb * 65536 + sc * 256 + sd
    end_num = ea * 16777216 + eb * 65536 + ec * 256 + ed
    
    ip_num >= start_num and ip_num <= end_num
  end
  
  defp fetch_content(url) do
    options = [
      follow_redirect: false,
      timeout: 10_000,
      recv_timeout: 10_000,
      max_redirect: 0
    ]
    
    case HTTPoison.get(url, [], options) do
      {:ok, %HTTPoison.Response{status_code: status_code}} when status_code in 300..399 ->
        {:error, :redirect_not_allowed}
      
      {:ok, %HTTPoison.Response{} = response} ->
        {:ok, response}
      
      {:error, %HTTPoison.Error{reason: reason}} ->
        {:error, reason}
    end
  end
end